const i=[{id:"low",label:"Sezon i ulët",labelEn:"Low Season",months:[1,2,11],multiplier:.85,badgeColor:"bg-blue-100 text-blue-700 border-blue-200",description:"Çmimet janë 15% më të ulëta gjatë muajve janar, shkurt dhe nëntor.",emoji:"❄️"},{id:"normal",label:"Sezon normal",labelEn:"Regular Season",months:[3,4,10,12],multiplier:1,badgeColor:"bg-neutral-100 text-neutral-600 border-neutral-200",description:"Çmimet standarde pa ndonjë shtesa ose zbritje sezonale.",emoji:"🌤️"},{id:"high",label:"Sezon i lartë",labelEn:"High Season",months:[5,6,9],multiplier:1.2,badgeColor:"bg-amber-100 text-amber-700 border-amber-200",description:"Kërkesa e lartë në maj, qershor dhe shtator: +20% mbi çmimin bazë.",emoji:"☀️"},{id:"peak",label:"Sezon kulminant",labelEn:"Peak Season",months:[7,8],multiplier:1.4,badgeColor:"bg-orange-100 text-orange-700 border-orange-200",description:"Korrik dhe gusht janë muajt me kërkesën më të lartë: +40% mbi çmimin bazë.",emoji:"🔥"}];function d(t=new Date){const e=t.getMonth()+1;return i.find(n=>n.months.includes(e))??i[1]}function h(t,e=new Date){const n=d(e);return Math.round(t*n.multiplier*100)/100}function c(t,e,n){const o=[],a=new Date(e);a.setHours(0,0,0,0);const u=new Date(n);for(u.setHours(0,0,0,0);a<u;){const r=d(a),s=Math.round(t*r.multiplier*100)/100,l=o.find(b=>b.season.id===r.id);l?(l.days+=1,l.subtotal=Math.round((l.subtotal+s)*100)/100):o.push({season:r,days:1,pricePerDay:s,subtotal:s}),a.setDate(a.getDate()+1)}const m=o.reduce((r,s)=>r+s.subtotal,0);return{total:Math.round(m*100)/100,breakdown:o}}function g(t,e){const{breakdown:n}=c(1,t,e);return n.length===0?i[1]:n.reduce((o,a)=>o.days>=a.days?o:a).season}function p(t){return i.map(e=>({season:e,pricePerDay:Math.round(t*e.multiplier*100)/100}))}export{h as a,g as b,c,p as d,d as g};
